import { useEffect, useState } from "react";
import { backendURL } from "../Globals";


let JournalsComponent = () => {

    let [journals, setJournals] = useState ([])
    let [message, setMessage] = useState("")


    useEffect ( () =>  {
    getJournals();
    }, [])


    return (
        <h2>Journals Component</h2>
    )

}






let getJournals = async () => {
    let response = await fetch(backendURL+"/journals") //aquĂ­ deberĂ­a ser journals?apikey, pero para eso deberĂ­a estar guardada en localstorage en LoginUSerComponent

    if (response.ok){
            let jsonData = await response.json()
            setJournals(jsonData)
    } else {
        setMessage("Error")
    }
}

export default JournalsComponent;
